mapper.select:
select *
from (
SELECT id,
content,
metadata,
ts_rank(content_tsvector, websearch_to_tsquery('jiebacfg', #{params.originalQuestion})) as score
FROM vector_store
WHERE content_tsvector @@ websearch_to_tsquery('jiebacfg', #{params.originalQuestion})

    AND (metadata ->> 'groupId') = #{params.groupId}::text


    AND (metadata ->> 'scopeType') = #{params.scopeType}


    AND (metadata ->> 'businessType') = #{params.businessType}


    AND (metadata ->> 'sourceType') = #{params.sourceType}


    AND (metadata ->> 'enablePublic') = #{params.enablePublic}::text

) t
where score > #{similarityThreshold}
ORDER BY score DESC
LIMIT #{topK}
